"use strict";(globalThis.webpackChunkp_foundation=globalThis.webpackChunkp_foundation||[]).push([[2355],{2493:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>i,default:()=>d,frontMatter:()=>s,metadata:()=>o,toc:()=>h});var o=t(9745),a=t(4848),r=t(8453);const s={title:"OpenCache: Local Caching for Every Provider",description:"The edge caching the hyperscalers built for themselves, now open to everyone. OpenCache serves any provider's content from inside local networks, keeping 80-97% of requests local in testing.",slug:"IntroducingOpenCache",authors:"jud",hide_table_of_contents:!1,date:new Date("2026-06-09T17:00:00.000Z")},i="OpenCache: Local Caching for Every Provider",c={authorsImageUrls:[void 0]},h=[{value:"The Gap an Exchange Can&#39;t Close",id:"the-gap-an-exchange-cant-close",level:2},{value:"How It Works",id:"how-it-works",level:2},{value:"Three Months of Real Traffic",id:"three-months-of-real-traffic",level:2},{value:"Get Involved",id:"get-involved",level:2}];function l(e){const n={a:"a",blockquote:"blockquote",em:"em",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.a,{href:"/updates/IntroducingOpenIXBeirut",children:"OpenIX Beirut"})," is just over a year old, and it has more than proven its premise. The exchange now runs as core infrastructure for the country's networks, and keeping Lebanon's traffic at home is no longer something we have to argue for."]}),"\n",(0,a.jsxs)(n.p,{children:["Getting here also taught us where the next gap is. An exchange localizes ",(0,a.jsx)(n.em,{children:"interconnection"}),": networks meet locally and trade traffic directly. It does not, by itself, localize ",(0,a.jsx)(n.em,{children:"content"}),". Today we are introducing ",(0,a.jsx)(n.strong,{children:"OpenCache"}),": an open caching network, built and operated by P Foundation, that serves content from inside the local network, for every content provider, not just the platforms big enough to build their own."]}),"\n",(0,a.jsx)(n.h2,{id:"the-gap-an-exchange-cant-close",children:"The Gap an Exchange Can't Close"}),"\n",(0,a.jsx)(n.p,{children:'Lebanon\'s traffic historically hairpinned through Europe (typically Marseille or Paris) even when both ends of a connection sat in Beirut. OpenIX fixed the interconnection half of that problem: networks now meet locally and trade traffic directly. But content still has to be served from somewhere, and for most providers that "somewhere" remained an origin or a CDN PoP on another continent.'}),"\n",(0,a.jsx)(n.p,{children:"Working at the exchange made the asymmetry impossible to miss. The large platforms solved content localization for themselves years ago with embedded cache programs: the Googles and Netflixes of the world ship their own appliances into ISPs and exchanges, and their traffic stays local. The moment OpenIX went live, they could plug in and benefit. Everyone else, from broadcasters and news organizations to software publishers and public institutions, has no practical way to do the same unless they build and operate their own CDN. As a result, the providers whose content often matters most to the community kept serving it from abroad, and their traffic kept leaving the country."}),"\n",(0,a.jsxs)(n.blockquote,{children:["\n",(0,a.jsx)(n.p,{children:"OpenIX localized the connections. OpenCache localizes the content."}),"\n"]}),"\n",(0,a.jsx)(n.h2,{id:"how-it-works",children:"How It Works"}),"\n",(0,a.jsx)(n.p,{children:"OpenCache is a fleet of cache nodes, placed at exchanges and inside ISP networks, all behind a single control plane that P Foundation operates. Nodes terminate TLS, speak HTTP/1.1, HTTP/2, and HTTP/3, serve from cache, and fetch from upstream (either IX or the provider's origin) on a miss, with always-on protections like request collapsing and stale-serving, ensuring origins never face a stampede. Each node is network-aware: a listen-only BGP session with its host network tells it exactly which prefixes are local to it, and health-driven steering shifts traffic away from a draining or saturated node before users notice. A node inside an ISP serves that ISP's subscribers and offloads its transit; a node at an exchange serves every network that peers there."}),"\n",(0,a.jsxs)(n.p,{children:["The governance is as deliberate as the engineering. The data plane is designed to spread; the control plane does not spread with it. ",(0,a.jsx)(n.strong,{children:"P Foundation always operates and maintains the control plane and the traffic policies, wherever the nodes sit."})," Hosting grants no control: cache rules and delivery policies are enforced identically across the fleet, TLS terminates inside the node, and a host network cannot reprioritize, alter, or selectively degrade the content its node serves. Neutrality is enforced by architecture, in the same way OpenIX offers the same terms to every participant."]}),"\n",(0,a.jsxs)(n.p,{children:["We are also releasing the edge side of the project as open source at ",(0,a.jsx)(n.a,{href:"https://github.com/pfoundation/opencache",children:"github.com/pfoundation/opencache"}),", allowing any ISP hosting a node, and any provider serving through one, to see exactly what runs at the edge."]}),"\n",(0,a.jsx)(n.h2,{id:"three-months-of-real-traffic",children:"Three Months of Real Traffic"}),"\n",(0,a.jsxs)(n.p,{children:["OpenCache is not launching as a promise. For the past three months we have been testing it with multiple content providers on production traffic, and the results show why local caching matters: cache effectiveness (the share of requests served straight from the local cache, without ever leaving the network) averaged ",(0,a.jsx)(n.strong,{children:"80-85% for live content"})," and ",(0,a.jsx)(n.strong,{children:"97% for on-demand content"}),". For on-demand, that means only about three requests in a hundred ever travel to the origin. Users get local latency, host ISPs shed transit they were paying for, and origins carry a fraction of their former load."]}),"\n",(0,a.jsx)(n.h2,{id:"get-involved",children:"Get Involved"}),"\n",(0,a.jsxs)(n.p,{children:["OpenCache is live today at ",(0,a.jsx)(n.a,{href:"/OpenIX/beirut",children:"OpenIX Beirut"}),"; any network peering at the exchange already reaches it over local peering, with no transit in the path. From here, the way in depends on who you are:"]}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Content providers"}),": ",(0,a.jsx)(n.a,{href:"/apply/opencache",children:"crate an account"})," and start serving instantly. You keep your origin and full authority over your content, and there is no requirement to operate your own CDN; that is precisely the gap OpenCache exists to fill. Where OpenCache does not yet have a footprint, partner CDNs keep your audience covered globally."]}),"\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Developers"}),": the OpenCache edge is open source. You are welcome to explore the code, open issues, and contribute at ",(0,a.jsx)(n.a,{href:"https://github.com/pfoundation/opencache",children:"github.com/pfoundation/opencache"}),"."]}),"\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Exchanges and communities"}),": ",(0,a.jsx)(n.a,{href:"/contact",children:"talk to us"})," about bringing OpenCache to your region."]}),"\n"]})]})}function d(e={}){const{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>s,x:()=>i});var o=t(6540);const a={},r=o.createContext(a);function s(e){const n=o.useContext(r);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function i(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),o.createElement(r.Provider,{value:n},e.children)}},9745:e=>{e.exports=JSON.parse('{"permalink":"/updates/IntroducingOpenCache","source":"@site/updates/2026-06-09-introducing_opencache.md","title":"OpenCache: Local Caching for Every Provider","description":"The edge caching the hyperscalers built for themselves, now open to everyone. OpenCache serves any provider\'s content from inside local networks, keeping 80-97% of requests local in testing.","date":"2026-06-09T17:00:00.000Z","tags":[],"readingTime":3.99,"hasTruncateMarker":true,"authors":[{"name":"Jud Saoud","title":"COO of P Foundation","email":"jud@p.foundation","imageURL":"https://github.com/judsd.png","key":"jud","page":null}],"frontMatter":{"title":"OpenCache: Local Caching for Every Provider","description":"The edge caching the hyperscalers built for themselves, now open to everyone. OpenCache serves any provider\'s content from inside local networks, keeping 80-97% of requests local in testing.","slug":"IntroducingOpenCache","authors":"jud","hide_table_of_contents":false,"date":"2026-06-09T17:00:00.000Z"},"unlisted":false,"lastUpdatedAt":1782396919000,"prevItem":{"title":"OpenIX Beirut: One Year Later","permalink":"/updates/OpenIXBeirutOneYearLater"},"nextItem":{"title":"2025 State of the Internet in Lebanon","permalink":"/updates/2025lb_state_of_internet"}}')}}]);